import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';
import LockIcon from './icons/LockIcon';
import AppLogoIcon from './icons/AppLogoIcon';
import UserIcon from './icons/UserIcon';
import EyeIcon from './icons/EyeIcon';
import EyeSlashIcon from './icons/EyeSlashIcon';
import CheckCircleIcon from './icons/CheckCircleIcon';
import ExclamationCircleIcon from './icons/ExclamationCircleIcon';


const Login: React.FC = () => {
    const { login, loginLoading } = useAuth();
    const { unlockAudio, isDataLoading, isCloud, error: dataError } = useData();

    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);
    const [error, setError] = useState('');

    const handleLoginSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        // فك حظر الصوت في المتصفح عند أول تفاعل
        unlockAudio();

        if (!username.trim() || !password.trim()) {
            setError('الرجاء إدخال اسم المستخدم وكلمة المرور.');
            return;
        }

        const result = await login(username, password, rememberMe);
        if (!result.success) {
            setError(result.message || 'فشل تسجيل الدخول.');
        }
    };

    return (
        <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-brand-dark to-[#3a7c93] relative overflow-hidden">
            <div className="absolute top-0 -left-4 w-72 h-72 bg-brand-light rounded-full mix-blend-screen filter blur-xl opacity-40 animate-blob"></div>
            <div className="absolute top-0 -right-4 w-72 h-72 bg-brand-accent-yellow rounded-full mix-blend-screen filter blur-xl opacity-40 animate-blob animation-delay-2000"></div>
            <div className="absolute -bottom-8 left-20 w-72 h-72 bg-brand-accent-red rounded-full mix-blend-screen filter blur-xl opacity-40 animate-blob animation-delay-4000"></div>

            <div className="w-full max-w-md p-8 space-y-6 bg-white/10 backdrop-blur-lg rounded-2xl shadow-2xl z-10">
                <div className="flex flex-col items-center text-center">
                    <div className="w-20 h-20 mb-6 transition-transform hover:scale-110 duration-500">
                        <AppLogoIcon />
                    </div>
                    <h2 className="text-3xl font-bold text-white tracking-tight">المهام اليومية</h2>
                    <p className="mt-2 text-sm text-gray-200 opacity-90">نظام تسجيل التقارير الداخلي</p>

                    <div className="mt-4 w-full flex items-center justify-center gap-2 py-2 px-4 bg-white/10 rounded-xl border border-white/5">
                        {isDataLoading ? (
                             <div className="flex items-center gap-2">
                                <div className="w-3 h-3 border-2 border-white/50 border-t-transparent rounded-full animate-spin"></div>
                                <span className="text-[10px] text-gray-200">جاري التحقق من الاتصال...</span>
                             </div>
                        ) : dataError ? (
                            <div className="flex items-center gap-2 text-brand-accent-yellow">
                                <ExclamationCircleIcon className="w-4 h-4" />
                                <span className="text-[10px] font-bold">خطأ في الربط مع Supabase</span>
                            </div>
                        ) : isCloud ? (
                            <div className="flex items-center gap-2 text-green-400">
                                <CheckCircleIcon className="w-4 h-4" />
                                <span className="text-[10px] font-bold">متصل بقاعدة البيانات السحابية</span>
                            </div>
                        ) : (
                            <span className="text-[10px] text-gray-200">أدخل بياناتك للمتابعة</span>
                        )}
                    </div>
                </div>

                <form className="mt-8 space-y-5" onSubmit={handleLoginSubmit}>
                    <div className="space-y-4 rounded-md">
                        <div className="relative group">
                            <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none transition-colors group-focus-within:text-brand-accent-yellow">
                                <UserIcon className="w-5 h-5 text-gray-300" />
                            </div>
                            <input 
                                id="username" 
                                name="username" 
                                type="text" 
                                autoComplete="username"
                                value={username} 
                                onChange={(e) => setUsername(e.target.value)} 
                                className="w-full px-3 py-3 text-white placeholder-gray-400 bg-white/10 border border-white/20 rounded-xl appearance-none pr-10 focus:outline-none focus:ring-2 focus:ring-brand-accent-yellow/50 focus:border-brand-accent-yellow transition-all sm:text-sm" 
                                placeholder="اسم المستخدم" 
                            />
                        </div>
                        <div className="relative group">
                            <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none transition-colors group-focus-within:text-brand-accent-yellow">
                                <LockIcon className="w-5 h-5 text-gray-300" />
                            </div>
                            <input 
                                id="password" 
                                name="password" 
                                type={showPassword ? 'text' : 'password'} 
                                autoComplete="current-password"
                                value={password} 
                                onChange={(e) => setPassword(e.target.value)} 
                                className="w-full px-3 py-3 text-white placeholder-gray-400 bg-white/10 border border-white/20 rounded-xl appearance-none pr-10 pl-10 focus:outline-none focus:ring-2 focus:ring-brand-accent-yellow/50 focus:border-brand-accent-yellow transition-all sm:text-sm" 
                                placeholder="كلمة المرور" 
                            />
                             <button 
                                type="button" 
                                onClick={() => setShowPassword(!showPassword)} 
                                className="absolute inset-y-0 left-0 flex items-center pl-3 hover:text-white transition-colors"
                                aria-label={showPassword ? "إخفاء كلمة المرور" : "إظهار كلمة المرور"}
                            >
                                {showPassword ? (
                                    <EyeSlashIcon className="w-5 h-5 text-gray-400" />
                                ) : (
                                    <EyeIcon className="w-5 h-5 text-gray-400" />
                                )}
                            </button>
                        </div>
                    </div>

                    <div className="flex items-center">
                        <input
                            id="remember-me"
                            name="remember-me"
                            type="checkbox"
                            checked={rememberMe}
                            onChange={(e) => setRememberMe(e.target.checked)}
                            className="w-4 h-4 text-brand-accent-yellow bg-white/10 border-white/20 rounded focus:ring-brand-accent-yellow"
                        />
                        <label htmlFor="remember-me" className="block mr-2 text-sm text-gray-200 select-none cursor-pointer">
                            تذكرني
                        </label>
                    </div>

                    {(error || dataError) && (
                        <p className="text-sm text-brand-accent-yellow text-center font-semibold bg-brand-accent-yellow/10 py-2 rounded-lg animate-pulse">
                            {error || dataError}
                        </p>
                    )}

                    <div>
                        <button 
                            type="submit" 
                            disabled={loginLoading || isDataLoading} 
                            className="relative flex justify-center w-full px-4 py-4 text-sm font-bold text-brand-dark bg-brand-accent-yellow border border-transparent rounded-xl group hover:bg-yellow-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-brand-dark focus:ring-brand-accent-yellow disabled:opacity-50 transition-all active:scale-95"
                        >
                            {loginLoading ? 'جارِ التحقق...' : (isDataLoading ? 'جاري الاتصال...' : 'دخول')}
                        </button>
                    </div>
                </form>

            </div>
            <footer className="absolute bottom-6 text-center text-xs text-gray-300/80 z-10">
                <p>© جميع الحقوق محفوظة 2025م</p>
                <p className="mt-1 font-semibold">تطوير: حسين كاظم</p>
            </footer>
        </div>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import XMarkIcon from './icons/XMarkIcon';
import SparklesIcon from './icons/SparklesIcon';
import AppLogoIcon from './icons/AppLogoIcon';

interface MaintenanceNoticeProps {
    userName: string;
}

const MaintenanceNotice: React.FC<MaintenanceNoticeProps> = ({ userName }) => {
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        // التحقق مما إذا كانت الرسالة قد عُرضت بالفعل في هذه الجلسة
        const hasSeenNotice = sessionStorage.getItem('maintenance_notice_seen');
        if (!hasSeenNotice) {
            const timer = setTimeout(() => {
                setIsVisible(true);
            }, 1000); // ظهور بعد ثانية من تحميل الواجهة لضمان الانتباه
            return () => clearTimeout(timer);
        }
    }, []);

    const handleDismiss = () => {
        setIsVisible(false);
        sessionStorage.setItem('maintenance_notice_seen', 'true');
    };

    if (!isVisible) return null;

    return (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-fade-in no-print">
            <div className="w-full max-w-lg bg-white dark:bg-gray-900 rounded-[2.5rem] shadow-2xl p-8 relative animate-scale-in border border-white/10 overflow-hidden">
                {/* خلفية جمالية خفيفة */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-brand-light/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                <div className="absolute bottom-0 left-0 w-24 h-24 bg-brand-accent-yellow/10 rounded-full -ml-12 -mb-12 blur-2xl"></div>

                <button 
                    onClick={handleDismiss}
                    className="absolute top-6 left-6 p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 bg-gray-50 dark:bg-gray-800 rounded-full transition-all active:scale-90"
                >
                    <XMarkIcon className="w-5 h-5" />
                </button>

                <div className="flex flex-col items-center text-center">
                    <div className="relative mb-6">
                        <div className="w-20 h-20 bg-brand-light/10 rounded-3xl flex items-center justify-center ring-4 ring-brand-light/5 animate-pulse">
                            <AppLogoIcon className="w-14 h-14" />
                        </div>
                        <div className="absolute -bottom-2 -right-2 bg-brand-accent-yellow p-1.5 rounded-xl shadow-lg border-2 border-white dark:border-gray-900">
                            <SparklesIcon className="w-5 h-5 text-brand-dark" />
                        </div>
                    </div>

                    <h3 className="text-2xl font-bold text-brand-dark dark:text-gray-100 mb-4">تنبيه أعمال تطوير</h3>

                    <div className="space-y-4 text-gray-600 dark:text-gray-300 leading-relaxed text-right">
                        <p className="font-bold text-brand-light text-lg">أهلاً بك، {userName.split(' ')[0]}</p>
                        <p className="text-sm md:text-base">
                            نود إحاطتكم علماً بأن التطبيق يخضع حالياً لعمليات <span className="text-brand-accent-yellow font-bold">صيانة وتطوير دورية</span> لتعزيز الأداء وإضافة ميزات جديدة.
                        </p>
                        <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-2xl border-r-4 border-brand-accent-yellow">
                            <p className="text-xs md:text-sm font-bold text-gray-700 dark:text-gray-200">
                                نرجو منكم الاستمرار في كتابة وتسجيل مهامكم اليومية كالمعتاد، حيث أن النظام يعمل بشكل كامل لاستقبال تقاريركم.
                            </p>
                        </div>
                        <p className="text-xs text-gray-500 dark:text-gray-400 italic">
                            شكراً لتفهمكم وتعاونكم الدائم معنا لتطوير بيئة العمل الرقمية.
                        </p>
                    </div>

                    <button 
                        onClick={handleDismiss}
                        className="mt-8 w-full py-4 bg-brand-dark dark:bg-brand-light text-white rounded-2xl font-bold text-lg hover:shadow-xl hover:scale-[1.02] transition-all shadow-lg active:scale-95"
                    >
                        حسناً، سأقوم بذلك
                    </button>
                </div>
            </div>
        </div>
    );
};

export default MaintenanceNotice;

import React from 'react';
import { AuthProvider, useAuth } from './context/AuthContext';
import { DataProvider, useData } from './context/DataContext';
import Login from './components/Login';
import EmployeeDashboard from './components/EmployeeDashboard';
import ManagerDashboard from './components/ManagerDashboard';
import { ThemeProvider } from './context/ThemeContext';
import ExclamationCircleIcon from './components/icons/ExclamationCircleIcon';
import InstallPWA from './components/InstallPWA';
import MaintenanceNotice from './components/MaintenanceNotice';

const AppContent: React.FC = () => {
    const { currentUser, loading: authLoading } = useAuth();
    const { isDataLoading, error } = useData();

    if (error) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 dark:bg-gray-900 p-4 text-center">
                 <div className="bg-white dark:bg-gray-800 p-8 rounded-lg shadow-xl max-w-md w-full border border-red-200 dark:border-red-900">
                    <ExclamationCircleIcon className="w-16 h-16 text-red-500 mx-auto mb-4" />
                    <h2 className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-2">خطأ في الاتصال</h2>
                    <p className="text-gray-600 dark:text-gray-300 mb-6">{error}</p>

                    {error.includes('relation') && (
                        <div className="text-sm text-left bg-gray-100 dark:bg-gray-700 p-3 rounded mb-4 overflow-x-auto text-gray-700 dark:text-gray-300">
                            <p className="font-semibold mb-1">الحل المقترح:</p>
                            <p>يبدو أن جداول قاعدة البيانات غير موجودة. يرجى الذهاب إلى Supabase SQL Editor وتشغيل الكود لإنشاء الجداول.</p>
                        </div>
                    )}

                    <button 
                        onClick={() => window.location.reload()}
                        className="w-full px-4 py-2 bg-brand-light text-white rounded hover:bg-brand-dark transition-colors"
                    >
                        إعادة المحاولة
                    </button>
                 </div>
            </div>
        );
    }

    if (authLoading || isDataLoading) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-100 dark:bg-gray-900">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-brand-light border-t-transparent rounded-full animate-spin mb-4"></div>
                    <div className="text-xl font-semibold text-gray-700 dark:text-gray-300">جاري الاتصال بقاعدة البيانات...</div>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
            {!currentUser ? <Login /> : (currentUser.role === 'employee' ? <EmployeeDashboard /> : <ManagerDashboard />)}
            {currentUser && <MaintenanceNotice userName={currentUser.fullName} />}
            <InstallPWA />
        </div>
    );
};

const App: React.FC = () => {
    return (
        <ThemeProvider>
            <DataProvider>
                <AuthProvider>
                    <AppContent />
                </AuthProvider>
            </DataProvider>
        </ThemeProvider>
    );
};

export default App;

